async (params, browser) => {
  // Open newsletter archive
  await browser.open(`https://${params.newsletter_slug}.substack.com/archive`)

  // Wait for archive to load
  await browser.waitForSelector('[class*=\'post\'], article, a[href*=\'/p/\'], [class*=\'archive\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more posts
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Scroll even further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract archive posts
  const archive_data = await browser.evaluate(`const posts = []; const postEls = document.querySelectorAll('[class*="post-preview"], article, [class*="post-item"], [class*="archive"] a[href*="/p/"]'); for (let i = 0; i < Math.min(postEls.length, 30); i++) { const el = postEls[i]; const titleEl = el.querySelector('h2, h3, [class*="post-title"], [class*="title"]'); const dateEl = el.querySelector('time, [class*="date"], [class*="timestamp"]'); const previewEl = el.querySelector('[class*="subtitle"], [class*="preview"], p'); const likesEl = el.querySelector('[class*="like"] span, [class*="heart"] span'); const commentsEl = el.querySelector('[class*="comment"] span'); const linkEl = el.tagName === 'A' ? el : el.querySelector('a[href*="/p/"]'); const isPaid = !!el.querySelector('[class*="paywall"], [class*="lock"], [class*="paid"]'); posts.push({ title: titleEl ? titleEl.textContent.trim() : '', preview: previewEl ? previewEl.textContent.trim().substring(0, 200) : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', likes: likesEl ? likesEl.textContent.trim() : '', comments: commentsEl ? commentsEl.textContent.trim() : '', is_paid: isPaid, url: linkEl ? linkEl.href : '' }); } return { newsletter: '' + params.newsletter_slug + '', post_count: posts.length, posts: posts, url: window.location.href }`)

  return archive_data
}
